mapper.select:
SELECT alba.alba_id AS albaId, work.work_id AS workId, work.work_status AS workStatus, work.work_date AS workDate, alba.alba_name AS albaName, alba.alba_phone AS albaPhone, alba.alba_status AS albaStatus FROM alba LEFT JOIN work ON alba.alba_id = work.alba_id
alba.store_id = #{storeId}
ORDER BY alba.alba_id DESC

SELECT COUNT(*) > 0
FROM alba
WHERE alba_id = #{albaId}

SELECT EXISTS (
    SELECT 1 FROM store WHERE store_id = #{storeId}
)

SELECT COUNT(*)
FROM alba
WHERE alba_phone = #{albaPhone}

mapper.update:
UPDATE alba
store_id = #{storeId}, alba_name = #{albaName}, alba_phone = #{albaPhone}, alba_status = #{albaStatus}, updated_at = NOW()
WHERE alba_id = #{albaId}

mapper.select:
SELECT COUNT(*)
FROM alba a
WHERE a.alba_id = #{albaId}
  AND a.store_id = #{storeId}
  AND a.is_active = b'1'
